/* Neural Local — embeddable chat widget
 * Usage on a client site:
 *   <script async src="https://YOUR-NEURAL-LOCAL-DOMAIN/embed.js"
 *           data-client-id="lumiere-med-spa"></script>
 *
 * That's it. Do not edit this file per-client — per-client data lives
 * in /clients/<clientId>.json on the Neural Local deployment.
 */
(function () {
  'use strict';

  // --- Find our own <script> tag to read data-client-id and the host URL ---
  var currentScript = document.currentScript;
  if (!currentScript) {
    // Fallback for async loaders that null out document.currentScript
    var scripts = document.getElementsByTagName('script');
    for (var i = scripts.length - 1; i >= 0; i--) {
      if (scripts[i].src && scripts[i].src.indexOf('embed.js') !== -1) {
        currentScript = scripts[i];
        break;
      }
    }
  }
  if (!currentScript) {
    console.error('[NeuralLocal] Could not locate embed script tag.');
    return;
  }

  var clientId = currentScript.getAttribute('data-client-id');
  if (!clientId) {
    console.error('[NeuralLocal] Missing data-client-id attribute on <script> tag.');
    return;
  }

  // The API base is the origin the script was loaded from.
  var apiBase = new URL(currentScript.src).origin;

  // Prevent double-injection if the script is loaded twice.
  if (window.__neuralLocalLoaded) return;
  window.__neuralLocalLoaded = true;

  // --- Inject scoped styles ---
  // All selectors are prefixed with .nl-wrap / .nl-toggle and use attribute
  // selectors where possible to minimize collisions with the host page.
  var css = [
    '.nl-toggle,.nl-wrap,.nl-wrap *{box-sizing:border-box;margin:0;padding:0;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,"Helvetica Neue",Arial,sans-serif}',
    '.nl-toggle{position:fixed;bottom:24px;right:24px;width:56px;height:56px;border-radius:50%;border:none;cursor:pointer;z-index:2147483646;display:flex;align-items:center;justify-content:center;box-shadow:0 4px 20px rgba(0,0,0,0.25);transition:transform .15s;background:#1a1a1a}',
    '.nl-toggle:hover{transform:scale(1.07)}',
    '.nl-toggle svg{width:22px;height:22px;fill:#f5f0e8}',
    '.nl-wrap{position:fixed;bottom:24px;right:24px;width:380px;height:560px;max-height:calc(100vh - 48px);border-radius:16px;overflow:hidden;box-shadow:0 8px 40px rgba(0,0,0,0.18);display:flex;flex-direction:column;background:#fff;z-index:2147483647;transition:opacity .2s,transform .2s}',
    '.nl-wrap.nl-hidden{opacity:0;pointer-events:none;transform:translateY(12px)}',
    '.nl-header{padding:14px 16px;display:flex;align-items:center;gap:10px;flex-shrink:0;background:#1a1a1a;color:#f5f0e8}',
    '.nl-avatar{width:36px;height:36px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:15px;font-weight:600;color:#1a1a1a;flex-shrink:0;background:#c9a97a}',
    '.nl-header-name{font-size:13px;font-weight:600;color:#f5f0e8}',
    '.nl-header-sub{font-size:11px;color:#aaa;margin-top:1px}',
    '.nl-status-dot{width:7px;height:7px;border-radius:50%;background:#5dcaa5;margin-left:auto;flex-shrink:0}',
    '.nl-close{background:none;border:none;color:#ccc;cursor:pointer;font-size:18px;padding:0 0 0 8px;line-height:1}',
    '.nl-powered{font-size:9px;color:#666;text-align:center;padding:4px;background:#111;letter-spacing:.08em;text-transform:uppercase;flex-shrink:0}',
    '.nl-messages{flex:1;overflow-y:auto;padding:14px 12px;display:flex;flex-direction:column;gap:9px;background:#faf9f7}',
    '.nl-msg{max-width:84%;font-size:13.5px;line-height:1.55;padding:9px 13px;border-radius:14px;animation:nlFade .2s ease;word-wrap:break-word}',
    '@keyframes nlFade{from{opacity:0;transform:translateY(5px)}to{opacity:1;transform:translateY(0)}}',
    '.nl-msg.nl-bot{background:#fff;color:#1a1a1a;border-radius:4px 14px 14px 14px;align-self:flex-start;border:0.5px solid #e8e3da}',
    '.nl-msg.nl-user{background:#1a1a1a;color:#f5f0e8;border-radius:14px 4px 14px 14px;align-self:flex-end}',
    '.nl-msg.nl-typing{background:#fff;border:0.5px solid #e8e3da;align-self:flex-start;border-radius:4px 14px 14px 14px;padding:12px 16px}',
    '.nl-typing-dots{display:flex;gap:4px;align-items:center}',
    '.nl-typing-dots span{width:5px;height:5px;border-radius:50%;background:#aaa;animation:nlBlink 1.2s infinite}',
    '.nl-typing-dots span:nth-child(2){animation-delay:.2s}',
    '.nl-typing-dots span:nth-child(3){animation-delay:.4s}',
    '@keyframes nlBlink{0%,80%,100%{opacity:.3}40%{opacity:1}}',
    '.nl-lead-tag{font-size:10px;background:rgba(201,169,122,0.13);color:#a07840;border:0.5px solid rgba(201,169,122,0.33);padding:2px 10px;border-radius:20px;align-self:center;letter-spacing:.04em;font-weight:500}',
    '.nl-input-area{padding:10px 12px;border-top:0.5px solid #e8e3da;display:flex;gap:8px;align-items:flex-end;flex-shrink:0;background:#fff}',
    '.nl-input{flex:1;border:0.5px solid #d8d3ca;border-radius:20px;padding:9px 14px;font-size:13px;resize:none;outline:none;background:#faf9f7;color:#1a1a1a;line-height:1.4;max-height:80px;overflow-y:auto}',
    '.nl-input:focus{border-color:#c9a97a}',
    '.nl-send{width:34px;height:34px;border-radius:50%;border:none;cursor:pointer;display:flex;align-items:center;justify-content:center;flex-shrink:0;transition:opacity .15s;background:#1a1a1a}',
    '.nl-send:hover{opacity:.8}',
    '.nl-send:disabled{opacity:.3;cursor:default}',
    '.nl-send svg{width:14px;height:14px;fill:#f5f0e8}',
    '.nl-msg a{color:#c9a97a;text-decoration:underline}',
    '@media (max-width:480px){.nl-wrap{width:calc(100vw - 24px);right:12px;bottom:12px;height:calc(100vh - 24px)}.nl-toggle{right:16px;bottom:16px}}'
  ].join('\n');

  var styleEl = document.createElement('style');
  styleEl.setAttribute('data-neural-local', '');
  styleEl.textContent = css;
  document.head.appendChild(styleEl);

  // --- Fetch client config, then render ---
  fetch(apiBase + '/.netlify/functions/config?clientId=' + encodeURIComponent(clientId))
    .then(function (r) {
      if (!r.ok) throw new Error('Config not found for client: ' + clientId);
      return r.json();
    })
    .then(function (cfg) { mountWidget(cfg); })
    .catch(function (e) {
      console.error('[NeuralLocal]', e.message);
    });

  function escapeHtml(s) {
    return String(s).replace(/[&<>"']/g, function (c) {
      return { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c];
    });
  }

  function linkify(text) {
    var escaped = escapeHtml(text);
    return escaped.replace(/(https?:\/\/[^\s<]+)/g, function (url) {
      return '<a href="' + url + '" target="_blank" rel="noopener noreferrer">' + url + '</a>';
    });
  }

  function applyTheme(theme) {
    if (!theme) return;
    // Allow client configs to override key colors via a small style patch.
    var overrides = [];
    if (theme.primary) {
      overrides.push('.nl-toggle,.nl-header,.nl-powered,.nl-msg.nl-user,.nl-send{background:' + theme.primary + ' !important}');
    }
    if (theme.accent) {
      overrides.push('.nl-avatar{background:' + theme.accent + ' !important}');
      overrides.push('.nl-msg a{color:' + theme.accent + ' !important}');
      overrides.push('.nl-input:focus{border-color:' + theme.accent + ' !important}');
    }
    if (overrides.length) {
      var s = document.createElement('style');
      s.setAttribute('data-neural-local-theme', '');
      s.textContent = overrides.join('\n');
      document.head.appendChild(s);
    }
  }

  function mountWidget(cfg) {
    applyTheme(cfg.theme);

    // --- Build DOM ---
    var toggle = document.createElement('button');
    toggle.className = 'nl-toggle';
    toggle.setAttribute('aria-label', 'Open chat');
    toggle.innerHTML = '<svg viewBox="0 0 24 24"><path d="M20 2H4c-1.1 0-2 .9-2 2v18l4-4h14c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2z"/></svg>';

    var wrap = document.createElement('div');
    wrap.className = 'nl-wrap nl-hidden';
    wrap.setAttribute('role', 'dialog');
    wrap.setAttribute('aria-label', cfg.assistantName + ' chat');
    wrap.innerHTML =
      '<div class="nl-header">' +
        '<div class="nl-avatar">' + escapeHtml(cfg.avatarLetter) + '</div>' +
        '<div style="flex:1;min-width:0">' +
          '<div class="nl-header-name">' + escapeHtml(cfg.assistantName) + (cfg.businessName ? ' — ' + escapeHtml(cfg.businessName) : '') + '</div>' +
          '<div class="nl-header-sub">Typically replies instantly</div>' +
        '</div>' +
        '<div class="nl-status-dot"></div>' +
        '<button class="nl-close" aria-label="Close chat">✕</button>' +
      '</div>' +
      '<div class="nl-powered">Powered by Neural Local AI</div>' +
      '<div class="nl-messages"></div>' +
      '<div class="nl-input-area">' +
        '<textarea class="nl-input" rows="1" placeholder="' + escapeHtml(cfg.placeholder) + '"></textarea>' +
        '<button class="nl-send" aria-label="Send">' +
          '<svg viewBox="0 0 24 24"><path d="M2 21l21-9L2 3v7l15 2-15 2z"/></svg>' +
        '</button>' +
      '</div>';

    document.body.appendChild(toggle);
    document.body.appendChild(wrap);

    var msgContainer = wrap.querySelector('.nl-messages');
    var input = wrap.querySelector('.nl-input');
    var sendBtn = wrap.querySelector('.nl-send');
    var closeBtn = wrap.querySelector('.nl-close');

    var messages = [];
    var leadCaptured = false;
    var isTyping = false;
    var chatOpened = false;

    function openChat() {
      wrap.classList.remove('nl-hidden');
      toggle.style.display = 'none';
      if (!chatOpened) {
        chatOpened = true;
        setTimeout(function () {
          addMessage('bot', cfg.greeting);
          messages.push({ role: 'assistant', content: cfg.greeting });
        }, 350);
      }
      input.focus();
    }

    function closeChat() {
      wrap.classList.add('nl-hidden');
      toggle.style.display = 'flex';
    }

    function addMessage(role, text) {
      if (role === 'typing') {
        var t = document.createElement('div');
        t.className = 'nl-msg nl-typing';
        t.setAttribute('data-nl-typing', '');
        t.innerHTML = '<div class="nl-typing-dots"><span></span><span></span><span></span></div>';
        msgContainer.appendChild(t);
        msgContainer.scrollTop = msgContainer.scrollHeight;
        return;
      }
      var el = document.createElement('div');
      el.className = 'nl-msg ' + (role === 'user' ? 'nl-user' : 'nl-bot');
      var cleaned = String(text).replace('[LEAD_CAPTURED]', '').trim();
      el.innerHTML = linkify(cleaned);
      msgContainer.appendChild(el);
      if (String(text).indexOf('[LEAD_CAPTURED]') !== -1 && !leadCaptured) {
        leadCaptured = true;
        var tag = document.createElement('div');
        tag.className = 'nl-lead-tag';
        tag.textContent = '✓ Lead captured';
        msgContainer.appendChild(tag);
      }
      msgContainer.scrollTop = msgContainer.scrollHeight;
    }

    function removeTyping() {
      var el = msgContainer.querySelector('[data-nl-typing]');
      if (el) el.remove();
    }

    function sendMessage(userText) {
      if (!userText.trim() || isTyping) return;
      isTyping = true;
      sendBtn.disabled = true;
      messages.push({ role: 'user', content: userText });
      addMessage('user', userText);
      input.value = '';
      input.style.height = 'auto';
      addMessage('typing');

      fetch(apiBase + '/.netlify/functions/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ clientId: clientId, messages: messages })
      })
        .then(function (r) { return r.json(); })
        .then(function (data) {
          removeTyping();
          var reply = data.reply || "Sorry, I had a hiccup — please try again!";
          messages.push({ role: 'assistant', content: reply });
          addMessage('bot', reply);
        })
        .catch(function () {
          removeTyping();
          addMessage('bot', "I'm having a moment — please try again shortly!");
        })
        .then(function () {
          isTyping = false;
          sendBtn.disabled = false;
        });
    }

    toggle.addEventListener('click', openChat);
    closeBtn.addEventListener('click', closeChat);
    sendBtn.addEventListener('click', function () { sendMessage(input.value); });
    input.addEventListener('keydown', function (e) {
      if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); sendMessage(input.value); }
    });
    input.addEventListener('input', function () {
      input.style.height = 'auto';
      input.style.height = Math.min(input.scrollHeight, 80) + 'px';
    });
  }
})();
